async def run_server(
    host: str = "0.0.0.0",
    port: int = 27015,
    *,
    mtu: int = DEFAULT_MTU,
    fragment_size: int = DEFAULT_FRAGMENT_SIZE,
    max_payload: int = DEFAULT_MAX_PAYLOAD,
    max_response_bytes: int = DEFAULT_MAX_RESPONSE_BYTES,
) -> None:
    loop = asyncio.get_running_loop()
    provider = StatusProvider()

    await provider.set_state(
        name=os.environ.get("GSS_NAME", "My Game Server"),
        map=os.environ.get("GSS_MAP", "default_map"),
        mode=os.environ.get("GSS_MODE", "deathmatch"),
        max_players=int(os.environ.get("GSS_MAX_PLAYERS", "64")),
        password=os.environ.get("GSS_PASSWORD", "0") in ("1", "true", "True", "yes", "YES"),
        version=os.environ.get("GSS_VERSION", "1.0.0"),
        region=os.environ.get("GSS_REGION", "global"),
        tags=[t for t in os.environ.get("GSS_TAGS", "").split(",") if t],
    )

    demo_players = []
    n = int(os.environ.get("GSS_DEMO_PLAYERS", "0"))
    for i in range(n):
        demo_players.append({"id": f"p{i+1}", "name": f"Player{i+1}", "score": i * 10, "ping": 20 + i, "team": None, "meta": {}})
    if demo_players:
        await provider.set_players(demo_players)

    transport, protocol = await loop.create_datagram_endpoint(
        lambda: UDPGameServer(
            provider,
            mtu=mtu,
            fragment_size=fragment_size,
            max_payload=max_payload,
            max_response_bytes=max_response_bytes,
            allow_any_ip=True,
        ),
        local_addr=(host, port),
        allow_broadcast=True,
    )

    sock = transport.get_extra_info("socket")
    if isinstance(sock, socket.socket):
        try:
            sock.setsockopt(socket.SOL_SOCKET, socket.SO_RCVBUF, 4 * 1024 * 1024)
        except Exception:
            pass
        try:
            sock.setsockopt(socket.SOL_SOCKET, socket.SO_SNDBUF, 4 * 1024 * 1024)
        except Exception:
            pass

    try:
        while True:
            await asyncio.sleep(3600)
    finally:
        transport.close()

def _build_status_query(request_id: int, include_players: bool = True, include_state: bool = True, include_meta: bool = True, max_players: Optional[int] = None) -> bytes:
    q: Dict[str, Any] = {
        "include_players": include_players,
        "include_state": include_state,
        "include_meta": include_meta,
    }
    if max_players is not None:
        q["max_players"] = int(max_players)
    payload = _safe_json_dumps(q)
    hdr = _pack_header(MSG_STATUS_QUERY, 0, request_id, 0, 1, len(payload), _crc32(payload))
    return hdr + payload

async def demo_client(host: str, port: int, timeout: float = 2.0) -> Dict[str, Any]:
    loop = asyncio.get_running_loop()
    request_id = int.from_bytes(os.urandom(4), "big")

    sock = socket.socket(socket.AF_INET, socket.SOCK_DGRAM)
    sock.setblocking(False)
    try:
        pkt = _build_status_query(request_id)
        await loop.sock_sendto(sock, pkt, (host, port))

        fragments: Dict[int, bytes] = {}
        total_expected: Optional[int] = None
        flags_seen: int = 0
        deadline = loop.time() + timeout

        while loop.time() < deadline:
            try:
                data, _addr = await asyncio.wait_for(loop.sock_recvfrom(sock, 65535), timeout=max(0.0, deadline - loop.time()))
            except asyncio.TimeoutError:
                break
            hdr = _unpack_header(data)
            if hdr is None:
                continue
            msg_type, flags, rid, seq, total, payload_len, payload_crc = hdr
            if rid != request_id or msg_type not in (MSG_STATUS_RESPONSE, MSG_ERROR):
                continue
            if len(data) < 22 + payload_len:
                continue
            payload = data[22:22 + payload_len]
            if _crc32(payload) != payload_crc:
                continue

            if msg_type == MSG_ERROR:
                if flags & FLAG_COMPRESSED:
                    payload = zlib.decompress(payload)
                return json.loads(payload.decode("utf-8"))

            flags_seen = flags
            if flags & FLAG_FRAGMENTED:
                total_expected = total
                fragments[seq] = payload
                if total_expected is not None and len(fragments) >= total_expected:
                    body = b"".join(fragments[i] for i in range(total_expected) if i in fragments)
                    if len(body) == sum(len(fragments[i]) for i in range(total_expected) if i in fragments):
                        if flags_seen & FLAG_COMPRESSED:
                            body = zlib.decompress(body)
                        return json.loads(body.decode("utf-8"))
            else:
                body = payload
                if flags & FLAG_COMPRESSED:
                    body = zlib.decompress(body)
                return json.loads(body.decode("utf-8"))

        return {"error": "timeout"}
    finally:
        sock.close()

